const HOOKDECK_API_KEY = process.env.HOOKDECK_API_KEY;
const ZEALT_RUN_ID = process.env.ZEALT_RUN_ID;
const SHOPIFY_WEBHOOK_SECRET = process.env.SHOPIFY_WEBHOOK_SECRET;

async function tryCreate(payload, label) {
  console.log(`\n--- Trying: ${label} ---`);
  try {
    const res = await fetch("https://api.hookdeck.com/2025-07-01/sources", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${HOOKDECK_API_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(payload),
    });
    console.log("Status:", res.status);
    const data = await res.json();
    console.log("Response:", JSON.stringify(data, null, 2));
    if (res.status >= 200 && res.status < 300) {
      return data;
    }
  } catch (err) {
    console.error("Error:", err.message);
  }
  return null;
}

async function run() {
  // Let's try option A (config with auth_type and auth)
  const name = `shopify-verify-${ZEALT_RUN_ID}-test`;
  const payloadA = {
    name: name + "-a",
    type: "SHOPIFY",
    config: {
      auth_type: "SHOPIFY",
      auth: {
        webhook_secret_key: SHOPIFY_WEBHOOK_SECRET
      }
    }
  };
  await tryCreate(payloadA, "Option A: config.auth_type and config.auth");

  // Let's try option B (verification object)
  const payloadB = {
    name: name + "-b",
    type: "SHOPIFY",
    verification: {
      type: "SHOPIFY",
      configs: {
        webhook_secret_key: SHOPIFY_WEBHOOK_SECRET
      }
    }
  };
  await tryCreate(payloadB, "Option B: verification object");

  // Let's try option C (config with auth)
  const payloadC = {
    name: name + "-c",
    type: "SHOPIFY",
    config: {
      auth: {
        webhook_secret_key: SHOPIFY_WEBHOOK_SECRET
      }
    }
  };
  await tryCreate(payloadC, "Option C: config.auth only");
}

run();

